{
  "clauseRiskSummary": "This clause outlines the Executive's employment terms, including notice periods and continuous employment requirements under Australian law. It does not address liability or financial obligations.",
  "operative_text": "The Executive's employment with the Company will commence on the Commencement Date and shall continue, subject to the remaining terms of this Agreement, until terminated by either party giving the other the following minimum advance written notice: 6 weeks' notice; such other longer period as required by law.",
  "concerns": [
    {
      "text": "The clause does not specify the definition of 'remaining terms of this Agreement', which could lead to ambiguity and disputes regarding the scope of employment.",
      "severity": "minor",
      "references": ["this Agreement"]
    }
  ],
  "favoursWhom": "neutral" 
}

{
  "clauseRiskSummary": "This clause outlines a pre-condition for the Executive's employment, requiring them to provide proof of legal work authorization in the UK. Failure to meet this condition could delay or prevent the Executive from commencing their role.",
  "operative_text": "The Executive's employment under this Agreement is conditional upon the Executive having produced to the Company for inspection original documents proving the Executive's right to work lawfully in the United Kingdom.",
  "concerns": [
    {
      "text": "Failure to provide proof of legal work authorization could delay or prevent the Executive from commencing their role, potentially impacting project timelines and deliverables.",
      "severity": "major",
      "references": ["Executive", "Company"]
    }
  ],
  "favoursWhom": "non-operator" 
}

{
  "clauseRiskSummary": "This clause outlines the responsibilities and duties of the Executive, potentially creating liability for the Client under joint and several liability provisions.",
  "operative_text": "The Executive shall serve as Chief Medical Officer and Senior Vice President, Development (reporting to Rick Winningham) or in such other role as the Company may determine. During the employment the Executive shall: devote the whole of their working time, attention and abilities to the business of the Company and any other Group Company for which the Executive is required to work from time to time; promptly make such reports to the Company in connection with the Executive's duties or other such matters at such times as are reasonably required; faithfully and diligently exercise such powers and perform such duties for each Group Company as may from time to time be assigned by the Company; comply with all reasonable and lawful directions given by the Company; report their own wrongdoing and any wrongdoing or proposed or potential wrongdoing of any other employee, officer or consultant of any Group Company to the Company immediately on becoming aware of it; use their utmost endeavours to promote, protect, develop and extend the business of the Company; comply with their common law, statutory, regulatory and fiduciary duties as well as any policies put in place by the Company from time to time; exercise the Executive's powers jointly with such other person that the Company may appoint; and at all times conduct the business of each Group Company for which the Executive is responsible in a lawful and ethical manner.",
  "concerns": [
    {
      "text": "Joint and several liability: The clause outlines potential joint and several liability for the Client under this contract, especially if the Executive's actions or omissions lead to financial losses or legal liabilities for the Client. ",
      "severity": "major",
      "references": ["Executive"]
    },
    {
      "text": "Capital call mechanics: The clause does not specify how capital calls are handled, which could create ambiguity and potential disputes regarding payment obligations.",
      "severity": "minor",
      "references": ["capital call mechanics"]
    }
  ],
  "favoursWhom": "non-operator" 
}

{
  "clauseRiskSummary": "This clause outlines the location and travel expectations for an Executive, potentially impacting the CLIENT's ability to manage risk or incur costs related to relocation.",
  "operative_text": "The normal place of work of the Executive is at the Executive’s home (or such other location as agreed between the Company and the Executive from time to time). The Executive agrees to travel on any business of any Group Company (both within the United Kingdom and abroad) as may be required for the proper performance of the Executive’s duties. The Executive shall not be required to work outside the United Kingdom for any continuous period of more than one month. If the Executive is required to do so, their terms of employment during this time will be communicated with them separately.",
  "concerns": [
    {
      "text": "The clause outlines a potential risk of relocation and travel expenses for the CLIENT's representative",
      "severity": "minor",
      "references": ["Executive", "United Kingdom"]
    }
  ],
  "favoursWhom": "non-operator" 
}

{
  "clauseRiskSummary": "This clause defines the standard work hours for the Executive, potentially impacting their availability and flexibility during project execution.",
  "operative_text": "The Executive shall work such hours as are required for the proper and efficient performance of their duties including the Company's normal business hours which are 9am until 5:30pm from Monday to Friday. The limit on weekly working time contained in Regulation 4 of The Working Time Regulations 1998 does not apply because Regulation 20 applies to the Executive.",
  "concerns": [
    {
      "text": "The clause defines specific work hours, which may impact flexibility and availability for the Executive during project execution. ",
      "severity": "minor",
      "references": ["Regulation 4 of The Working Time Regulations 1998", "Regulation 20"]
    }
  ],
  "favoursWhom": "non-operator" 
}

{
  "clauseRiskSummary": "Clause 7 outlines salary payment mechanics and potential for deductions, including reimbursement for unauthorized expenses. It also mentions a review process with no obligation to increase the salary.",
  "operative_text": "The Executive shall be paid a basic salary of £448,903 per annum subject to deductions required by law. The Executive's salary shall accrue from day to day, shall be payable in equal monthly instalments in arrears on or about the last day of each month.",
  "concerns": [
    {
      "text": "The clause mentions 'deductions required by law', which could potentially expose the CLIENT to unexpected financial obligations and liabilities. ",
      "severity": "major",
      "references": ["clause 7.1"]
    },
    {
      "text": "The clause states that the Executive's salary will be reviewed on or around 1 April 2021, but there is no obligation to increase the salary following this review.",
      "severity": "minor",
      "references": ["clause 7.2"]
    },
    {
      "text": "The clause mentions that the Company may deduct from the Executive's salary any money owed to any Group Company by the Executive, and the Executive will reimburse the Company upon demand for personal use of company credit cards or unauthorized transactions.",
      "severity": "major",
      "references": ["clause 7.3"]
    }
  ],
  "favoursWhom": "non-operator" 
}

{
  "clauseRiskSummary": "This clause outlines reimbursement for travel expenses incurred by an executive, but lacks clarity on expense categories, reimbursement process, and potential disputes over reasonableness.",
  "operative_text": "Expenses The Company shall reimburse any reasonable travel expenses wholly, exclusively and necessarily incurred by the Executive in the proper performance of the Executive's duties under this Agreement subject always to the rules and policies of the Company from time to time and subject to the Executive providing receipts or other evidence of payment as the Company may require.",
  "concerns": [
    {
      "text": "The clause lacks clarity on what constitutes 'reasonable travel expenses', leaving room for disputes over reimbursement amounts.",
      "severity": "major",
      "references": ["Expenses The Company"]
    },
    {
      "text": "The clause mentions 'rules and policies of the Company' which could lead to arbitrary or inconsistent expense reimbursements.",
      "severity": "major",
      "references": ["rules and policies of the Company"]
    }
  ],
  "favoursWhom": "non-operator" 
}

{
  "clauseRiskSummary": "This clause grants significant discretion to the company regarding bonus payments, potentially exposing the client (Acme Holdings) to financial risk and lack of clarity on payment terms.",
  "operative_text": "9.2 The Company may suspend, alter or discontinue any bonus payment(s) or any bonus plan and its eligibility requirements at any time (whether generally or in relation to the Executive only) at its absolute discretion. If the Executive receives any bonus payment the Company is not obliged to make any further bonus payments and any bonus payment will not become part of the Executive's contractual remuneration or fixed salary.",
  "concerns": [
    {
      "text": "The clause grants the company significant discretion in determining bonus eligibility, including the ability to suspend, alter, or discontinue the plan at any time. This could expose the client to financial risk and lack of clarity on payment terms.",
      "severity": "major",
      "references": ["9.2"]
    },
    {
      "text": "The clause states that if the Executive receives a bonus, the company is not obliged to make further payments. This could create uncertainty regarding future compensation and leave the client exposed to financial risk.",
      "severity": "major",
      "references": ["9.2"]
    }
  ],
  "favoursWhom": "operator" 
}

{
  "clauseRiskSummary": "This clause outlines the Company's intention to comply with Australian pension regulations for executives, but it also grants significant flexibility in managing the pension scheme, potentially exposing the CLIENT to unforeseen changes and liabilities.",
  "operative_text": "The Company intends to comply with the employer pension duties in respect of the Executive in accordance with Part 1 of the Pensions Act 2008. The Executive's participation in the Company's pension arrangements is subject to the rules of the relevant scheme and the statutory requirement as each are varied from time to time. In particular the Company reserves the right to change the scheme provider, the funds available, the charging structure and the default fund from time to time.",
  "concerns": [
    {
      "text": "The clause grants the Company significant flexibility in managing the pension scheme, potentially exposing the CLIENT to unforeseen changes and liabilities.",
      "severity": "major",
      "references": ["Company", "Pension Act 2008", "scheme provider", "funds available", "charging structure", "default fund"]
    }
  ],
  "favoursWhom": "non-operator" 
}

{
  "clauseRiskSummary": "This clause outlines potential risks for the CLIENT regarding benefits during employment, including the Company's right to modify or discontinue these plans without notice.",
  "operative_text": "The Executive may participate in benefit plans operated by the Company. The Executive's participation in any such benefit plans are subject to the terms and conditions of any such plan. The Company reserves the right to discontinue, vary or amend each benefit plan (including the level of cover) at any time on reasonable notice to the Executive.",
  "concerns": [
    {
      "text": "The clause grants the COMPANY broad discretion over benefits, potentially impacting CLIENT's financial security and access to benefits.",
      "severity": "major",
      "references": ["Company", "Executive", "benefit plans"]
    }
  ],
  "favoursWhom": "non-operator" 
}

{
  "clauseRiskSummary": "This clause outlines the Executive's paid holiday entitlement, including calculation for partial years and provisions for excess days upon termination. It also addresses the Company's right to recover unused holiday days upon termination.",
  "operative_text": "The Executive shall be entitled to 28 days' paid holiday in each holiday year (which includes public holidays) to be taken at times convenient to the Company and authorised in advance. If the Executive's employment commences or terminates part way through a holiday year, the Executive's entitlement during that holiday year shall be calculated on a pro rata basis rounded up to the nearest whole day.",
  "concerns": [
    {
      "text": "The clause defines 'holiday year' as running from 1 January to 31 December. This could create issues if the client's business operates outside of this timeframe, potentially impacting holiday accrual and usage.",
      "severity": "minor",
      "references": ["operative_text"]
    },
    {
      "text": "The clause outlines a pro-rata calculation for holidays taken during partial years. This could lead to disputes if the company's definition of 'holiday year' differs from the client's understanding.",
      "severity": "minor",
      "references": ["operative_text"]
    },
    {
      "text": "The clause specifies that unused holiday days can be deducted upon termination. This could lead to financial disputes if the company and client disagree on the calculation of excess days or the amount of payment in lieu.",
      "severity": "major",
      "references": ["operative_text"]
    }
  ],
  "favoursWhom": "non-operator" 
}

{
  "clauseRiskSummary": "This clause outlines a Company Sick Pay policy for executives, but it also includes provisions that could lead to potential disputes regarding the Executive's entitlement to sick pay and benefits.",
  "operative_text": "13. Sickness 13.1 The Company may in its absolute discretion pay the Executive an amount equal to the Executive’s normal basic pay (“Company Sick Pay”) for the first 3 months of sickness absence in any rolling 12-month period, subject to such conditions as the Company may specify. Company Sick Pay will include any entitlement to statutory sick pay or any benefits provided by virtue of any permanent health insurance scheme. Company Sick Pay is also subject to the Executive’s compliance with this Agreement and will not be paid in respect of any period of illness that commences during the first 6 months of the Executive's employment or whilst the Company is addressing performance or disciplinary issues. 13.2 The Executive must comply with the Company’s sickness absence notification procedures. Any period of absence of up to five days may be self-certified and any period of absence of more than five days must be supported by doctor’s certificate. 13.3 The Executive consents to undergo a medical examination by a doctor nominated by the Company at the Company's request and expense. The Executive agrees that any report produced in connection with any such examination may be disclosed to the Company and the Company may discuss the contents of any such report with the relevant doctor.",
  "concerns": [
    {
      "text": "The clause grants the company discretion over sick pay, which could lead to disputes regarding the Executive's entitlement to benefits.",
      "severity": "major",
      "references": ["Company Sick Pay"]
    },
    {
      "text": "The clause specifies that the Executive must comply with the Company’s sickness absence notification procedures. This could create a potential for conflict between the Executive and the company regarding the timing of notifications.",
      "severity": "minor",
      "references": ["Sickness Absence Notification Procedures"]
    },
    {
      "text": "The clause grants the company discretion over sick pay, which could lead to disputes regarding the Executive's entitlement to benefits.",
      "severity": "major",
      "references": ["Company Sick Pay"]
    }
  ],
  "favoursWhom": "non-operator" 
}

{
  "clauseRiskSummary": "This clause outlines restrictions on the Executive's outside activities, potentially impacting their ability to engage in investments or other business ventures during employment.",
  "operative_text": "The Executive shall not during the employment except as a representative of the Company or with the Company’s prior written consent (whether directly or indirectly, paid or unpaid) be employed, engaged, concerned or interested in any other actual or prospective business, organisation, occupation or profession. Nothing in this Agreement shall prevent the Executive from holding an investment by way of shares or other securities to in any entity listed or dealt on a recognised stock exchange (a \"Permitted Investment\") provided always that during the term of the employment the Permitted Investment shall not constitute more than 3% of the issued share capital of the entity concerned.",
  "concerns": [
    {
      "text": "The clause restricts outside activities, potentially impacting investment opportunities and business ventures. The 'Permitted Investment' limit (3%) may be restrictive for certain investments.",
      "severity": "major",
      "references": ["Executive", "Company", "investment", "Permitted Investment", "3%"]
    }
  ],
  "favoursWhom": "non-operator" 
}

{
  "clauseRiskSummary": "This clause outlines confidentiality obligations for the Executive, potentially impacting the CLIENT's ability to share information with third parties or disclose it in public forums.",
  "operative_text": "15.1 Without prejudice to the Executive’s common law and fiduciary duties, the Executive shall not during employment or at any time after Termination and whether for their own benefit or for the benefit of any third party: 15.1.1 use any Confidential Information; or 15.1.2 disclose any Confidential Information to any person, company or other organisation whatsoever, except in the proper course of their duties, as required by law or as authorised by the Company in writing.",
  "concerns": [
    {
      "text": "The clause outlines confidentiality obligations for the Executive, potentially impacting the CLIENT's ability to share information with third parties or disclose it in public forums.",
      "severity": "major",
      "references": ["Executive"]
    }
  ],
  "favoursWhom": "non-operator" 
}

{
  "clauseRiskSummary": "This clause grants the Company full ownership rights over all Intellectual Property created by the Executive during their employment, even if it's jointly developed. It also waives moral rights and appoints the Company as the Executive's attorney to execute documents for the benefit of the Company.",
  "operative_text": "16. Intellectual Property 16.1 The Executive shall disclose to the Company details of all Inventions and of all works embodying Intellectual Property Rights made solely or jointly with others at any time during the term of the employment which relate to, or are capable of being used in, the business of any Group Company whether or not in the course of their ordinary duties and whether or not made in working time (together, the \"Company IP\"). The Executive acknowledges that all Intellectual Property Rights subsisting (or which may in the future subsist) in such Company IP shall automatically, on creation, vest in the Company absolutely. To the extent that the Company IP does not vest automatically in the Company the Executive hereby assigns all right, title and interest in the Company IP to the Company with full title guarantee by way of a present assignment of all future rights and shall otherwise hold them on trust for the Company. The Executive agrees promptly to execute all documents and to do all acts as may, in the opinion of the Company, be necessary or desirable to give the Company full benefit of this clause.",
  "concerns": [
    {
      "text": "The clause grants the Company absolute ownership rights over all Intellectual Property created by the Executive during their employment, even if it's jointly developed. This could lead to significant risk for the CLIENT if the Executive creates valuable IP that is later used in a way that benefits the COMPANY.",
      "severity": "major",
      "references": ["Company IP"]
    },
    {
      "text": "The clause waives moral rights under the Copyright, Designs and Patents Act 1988 (and, to the fullest extent permitted by law, all similar rights in other jurisdictions) which the Executive has or will have in any Company IP. This could expose the CLIENT to legal challenges if the Executive's work is later used in a way that infringes on third-party intellectual property rights.",
      "severity": "major",
      "references": ["Copyright, Designs and Patents Act 1988"]
    },
    {
      "text": "The clause appoints the Company as the Executive's attorney to execute any instrument or to do anything and generally to use the Executive's name for the purpose of giving the Company or i ts nominee the benefit  of this clause. This could expose the CLIENT to legal challenges if the Executive's work is later used in a way that infringes on third-party intellectual property rights.",
      "severity": "major",
      "references": ["Company"]
    }
  ],
  "favoursWhom": "company" 
}

{
  "clauseRiskSummary": "This clause outlines a 'Payment in Lieu of Notice' (PILON) mechanism for terminating an executive's employment, granting the Company significant discretion and potentially exposing the CLIENT to financial risk.",
  "operative_text": "17. Payment in Lieu of Notice 17.1 The Company may, in its sole and absolute discretion, terminate the Executive's employment under this Agreement at any time and with immediate effect by notifying the Executive that the Company is exercising its right under this clause 17 and that it will make a payment in lieu of notice ('PILON') to the Executive. The Executive's employment will terminate immediately and any PILON due to the Executive in accordance with the provisions of this clause 17 will be paid within 28 days. The PILON will be equal to the basic salary (as at the Termination Date) which the Executive would have been entitled to receive under this Agreement during the notice period referred to at clause 2 (or, if notice has already been given, during the remainder of the notice period) less deductions required by law. 17.2 The Executive shall have no right to receive a PILON unless the Company has exercised its discretion in clause 17.1. 17.3 Notwithstanding clause 17.1, the Executive shall not be entitled to any PILON if the Company would otherwise have been entitled to terminate the Executive's employment under this Agreement without notice in accordance with clause 18. In that case the Company shall also be entitled to recover from the Executive any PILON already made.",
  "concerns": [
    {
      "text": "The CLIENT is exposed to potential financial risk as the COMPANY has sole discretion over termination and payment of PILON, potentially leading to significant losses if not properly managed.",
      "severity": "major",
      "references": ["clause 17.1", "PILON"]
    },
    {
      "text": "The clause outlines a 'capital call' mechanism for the COMPANY to terminate employment with immediate effect, potentially exposing the CLIENT to financial risk and loss of rights.",
      "severity": "major",
      "references": ["clause 17.1", "PILON"]
    },
    {
      "text": "The clause outlines a 'capital call' mechanism for the COMPANY to terminate employment with immediate effect, potentially exposing the CLIENT to financial risk and loss of rights.",
      "severity": "major",
      "references": ["clause 17.1", "PILON"]
    },
    {
      "text": "The clause outlines a 'capital call' mechanism for the COMPANY to terminate employment with immediate effect, potentially exposing the CLIENT to financial risk and loss of rights.",
      "severity": "major",
      "references": ["clause 17.1", "PILON"]
    }
  ],
  "favoursWhom": "operator"
}

{
  "clauseRiskSummary": "This clause grants the Company significant power to terminate the Executive's employment without notice or further payment, even for minor breaches or non-observances of the Agreement. This could expose the CLIENT to substantial financial and reputational risk.",
  "operative_text": "18.1 The Company may terminate the Executive’s employment under this Agreement with immediate effect without notice and with no liability to make any further payment to the Executive (other than in respect of amounts accrued at the Termination Date) if in the reasonable opinion of the Company the Executive: 18.1.1 is guilty of gross misconduct; or 18.1.2 commits any serious or repeated breach or non-observance of any of the provisions of this Agreement or refuses to comply with any reasonable and lawful directions of the Company; or 18.1.3 commits any serious or repeated breach of the Company’s policies or procedures; or 18.1.4 is grossly negligent or grossly incompetent in the performance of their duties; 18.1.5 is declared bankrupt or makes any arrangement with or for the benefit of their creditors or has a county court administration order made under the County Court Act 1984; or 18.1.6 is convicted of any criminal offence (other than an offence under any road traffic legislation in the United Kingdom or elsewhere for which a fine or non-custodial penalty is imposed); or 18.1.7 is no longer eligible to work in the United Kingdom; or 18.1.8 is guilty of any fraud or dishonesty or acts in any manner which brings or is likely to bring the Executive or any Group Company into disrepute or is materially adverse to the interests of any Group Company; or 18.1.9 makes any statement or other form of communication that disparages or undermines the goodwill or reputation of any Group Company.",
  "concerns": [
    {
      "text": "The clause grants the Company significant power to terminate the Executive's employment without notice or further payment, even for minor breaches or non-observances of the Agreement. This could expose the CLIENT to substantial financial and reputational risk.",
      "severity": "major",
      "references": ["18.1"]
    },
    {
      "text": "The clause grants the Company significant power to terminate the Executive's employment without notice or further payment, even for minor breaches or non-observances of the Agreement. This could expose the CLIENT to substantial financial and reputational risk.",
      "severity": "major",
      "references": ["18.1"]
    }
  ],
  "favoursWhom": "non-operator" 
}

{
  "clauseRiskSummary": "This clause outlines the terms for placing an Executive on Garden Leave following termination of employment, potentially impacting their compensation and access to company resources.",
  "operative_text": "Following service of notice to terminate the employment by either party, or if the Executive purports to terminate the employment in breach of contract, the Company may by written notice place the Executive on Garden Leave for the whole or part of the remainder of the employment. During any period of Garden Leave: 19.2.1 the Company shall be under no obligation to provide any work to the Executive and may revoke any powers the Executive holds on behalf of any Group Company; 19.2.2 the Executive shall continue to receive their basic salary but shall not be entitled to receive any bonus or other incentives in respect of the period of Garden Leave; 19.2.3 the Company may require the Executive to carry out alternative duties or to only perform such specific duties as are expressly assigned to the Executive, at such location (including the home of the Executive) as the Company may reasonably decide; 19.2.4 the Company may appoint another person to carry out the Executive’s normal duties; 19.2.5 the Executive shall remain an employee of the Company and bound by the terms of this Agreement; 19.2.6 the Executive shall be contactable during each working day (except during any periods taken as holiday in the usual way); 19.2.7 the Company may exclude the Executive from any premises of any Group Company, require the Executive to return any Group Company property and remove the Executive’s access from some or all of its information systems; and 19.2.8 the Company may require the Executive not to contact or deal with (or attempt to contact or deal with) any officer, employee, consultant, client or other business contact of any Group Company as it may reasonably determine.",
  "concerns": [
    {
      "text": "The clause outlines potential for the company to place an executive on Garden Leave following termination of employment. This could result in loss of income and access to resources.",
      "severity": "major",
      "references": ["19.2.1", "19.2.2", "19.2.3", "19.2.4", "19.2.5", "19.2.6", "19.2.7", "19.2.8"]
    },
    {
      "text": "The clause outlines the potential for the company to revoke powers held by the executive, potentially impacting their ability to perform duties and access resources.",
      "severity": "major",
      "references": ["19.2.1", "19.2.2"]
    },
    {
      "text": "The clause outlines potential for the company to exclude the executive from premises of any group company, requiring return of property and removal of access to information systems.",
      "severity": "major",
      "references": ["19.2.7"]
    }
  ],
  "favoursWhom": "non-operator" 
}

{
  "clauseRiskSummary": "This clause outlines obligations for an Executive upon termination, including immediate handover of business information and data deletion. Failure to comply could lead to legal disputes or financial penalties.",
  "operative_text": "20.1.1 immediately deliver to the Company all documents, books, materials, records, correspondence, papers, Copies, Confidential Information and other business information (on whatever media and wherever located) relating to the business or affairs of any Group Company or its business contacts, any keys and any other property of any Group Company, which is in the Executive's possession or control; 20.1.2 irretrievably delete any information relating to the business of any Group Company stored on any magnetic or optical disk or memory (including on any personal computer, personal device, personal email account or web account), and all matter derived from such sources which is in their possession or under their control outside the premises of the Company; 20.1.3 provide such handover of their duties as the Company shall consider appropriate; and 20.1.4 provide a signed statement confirming full compliance with the obligations under clauses 20.1.1 and 20.1.2 together with such reasonable evidence of compliance as the Company may request.",
  "concerns": [
    {
      "text": "The clause mandates immediate handover of all business information, including confidential data and property, upon termination. Failure to comply could result in legal disputes or financial penalties.",
      "severity": "major",
      "references": ["20.1.1", "Confidential Information"]
    },
    {
      "text": "The clause mandates irretrievable deletion of business-related data stored on personal devices and accounts upon termination, potentially exposing the Executive to legal risks.",
      "severity": "major",
      "references": ["20.1.2", "Executive"]
    }
  ],
  "favoursWhom": "non-operator" 
}

{
  "clauseRiskSummary": "This clause restricts the Executive's post-employment actions regarding employee recruitment, potentially impacting their ability to influence company staffing decisions.",
  "operative_text": "Post Termination Restrictions During the term of employment and for one (1) year thereafter, the Executive will not directly or indirectly, either themselves or through others, encourage or solicit any employee of the Company to leave the Company for any reason. This obligation shall not affect any responsibility the Executive has as an employee of the Company with respect to the bona fide hiring and firing of Company personnel.",
  "concerns": [
    {
      "text": "The clause restricts the Executive's post-employment actions regarding employee recruitment, potentially impacting their ability to influence company staffing decisions. This could be a major concern if the Executive has significant influence over hiring or firing decisions.",
      "severity": "major",
      "references": ["Executive", "Company", "employee"]
    }
  ],
  "favoursWhom": "non-operator" 
}

{
  "clauseRiskSummary": "This clause outlines the grievance and appeal process for the Executive, but does not form part of their contract of employment. It also clarifies that there is no collective agreement affecting their employment or this Agreement.",
  "operative_text": "22.1 The Executive is subject to the Company's disciplinary and grievance procedures, copies of which are available upon request (although the Company reserves the right to deviate from these procedures in light of the Executive's seniority). These procedures do not form part of the Executive's contract of employment. 22.2 If the Executive wishes to raise a grievance or appeal a disciplinary decision the matter should be raised in writing with Rick Winningham. 22.3 There is no collective agreement which affects the Executive's employment or this Agreement.",
  "concerns": [
    {
      "text": "The clause mentions 'grievance procedures' and 'disciplinary decisions', but does not specify how these relate to the CLIENT's obligations under the contract, potentially creating ambiguity regarding liability for breaches of contract by the Executive.",
      "severity": "major",
      "references": ["Executive", "contract"]
    }
  ],
  "favoursWhom": "non-operator" 
}

{
  "clauseRiskSummary": "This clause grants the Company broad monitoring rights over the Executive's communication and electronic equipment, potentially impacting privacy and confidentiality.",
  "operative_text": "The Executive's attention is drawn to the Company's Privacy Notice which is available upon request. The Executive consents to the Company monitoring their communication and electronic equipment including, without limitation, the Company's telephone, chat and e-mail systems, information stored on the Company's computer equipment (including all electronically stored information that is the property of the Company), recordings from the Company's closed circuit television cameras and any other computer equipment or other device used by the Executive in the performance of their duties.",
  "concerns": [
    {
      "text": "The clause grants broad monitoring rights over the Executive's communication and electronic equipment, potentially impacting privacy and confidentiality. This could lead to legal challenges if the company uses this information for purposes not explicitly agreed upon by the Executive.",
      "severity": "major",
      "references": ["Executive", "communication", "electronic equipment", "Company's telephone", "chat and e-mail systems", "information stored on the Company's computer equipment", "recordings from the Company's closed circuit television cameras", "any other computer equipment or other device used by the Executive in the performance of their duties"]
    }
  ],
  "favoursWhom": "non-operator" 
}

